example.code:
# typed: strict
# frozen_string_literal: true

class UserMailer
  extend T::Sig

  sig { params(user: User).returns(Mail::Message) }
  def self.welcome(user)
    new.welcome(user)
  end

  sig { params(user: User).returns(Mail::Message) }
  def welcome(user)
    Mail.new(to: user.email, subject: "Welcome")
  end
end
